let items=$input.all(),r=[];
for(let it of items){
 let d=it.json,body=d.body||d,msg=body.message||body.edited_message||body;
 if(!msg||!msg.text){r.push({json:{_skip:true}});continue}
 let chat=msg.chat||{},from=msg.from||{},text=msg.text||'',cid=String(chat.id),name=[from.first_name,from.last_name].filter(Boolean).join(' ')||from.username||'User';
 let prompt='You are Digital Clone, helpful AI. Be concise.\nUser ('+name+') says: '+JSON.stringify(text)+'\nReply in plain text, under 500 chars.';
 r.push({json:{_prompt:prompt,_chat_id:cid,_reply_to:msg.message_id}})
}
return r

let items=$input.all(),r=[],pn=$('Build Prompt');
for(let i=0;i<items.length;i++){
 let d=items[i].json,orig=pn?pn.item.json:{},raw=d.response||'',reply=String(raw).trim().substring(0,3500)||'OK';
 r.push({json:{_reply:reply,_chat_id:d._chat_id||orig._chat_id||'',_reply_to:d._reply_to||orig._reply_to}})
}
return r
